import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;
import org.owasp.esapi.ESAPI;
import org.owasp.esapi.errors.EncodingException;

public class SecureServlet extends HttpServlet {
    protected void doGet(HttpServletRequest request, HttpServletResponse response)
            throws ServletException, IOException {
        String userInput = request.getParameter("input");
        String safeOutput = "";

        try {
            safeOutput = "<p>User Input: " + ESAPI.encoder().encodeForHTML(userInput) + "</p>";
        } catch (EncodingException e) {
            // Handle encoding exception
            safeOutput = "<p>Error processing user input</p>";
        }

        PrintWriter out = response.getWriter();
        out.println("<html><head><title>Secure Code Example</title></head><body>");
        out.println(safeOutput);
        out.println("</body></html>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
